"use strict";(globalThis.webpackChunkbook=globalThis.webpackChunkbook||[]).push([[3216],{102(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_1_introduction_to_physical_ai","label":"Chapter 1: Introduction to Physical AI","docId":"chapter_1_introduction_to_physical_ai","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_2_embodied_intelligence","label":"Chapter 2: Embodied Intelligence","docId":"chapter_2_embodied_intelligence","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_3_ros2_fundamentals","label":"Chapter 3: ROS2 Fundamentals","docId":"chapter_3_ros2_fundamentals","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_4_ros2_advanced","label":"Chapter 4: ROS2 Advanced","docId":"chapter_4_ros2_advanced","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_5_robot_simulation_gazebo","label":"Chapter 5: Robot Simulation Gazebo","docId":"chapter_5_robot_simulation_gazebo","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_6_unity_for_robotics","label":"Chapter 6: Unity for Robotics","docId":"chapter_6_unity_for_robotics","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_7_nvidi-isaac_platform","label":"Chapter 7: NVIDIA Isaac Platform","docId":"chapter_7_nvidi-isaac_platform","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_8_humanoid_robot_development","label":"Chapter 8: Humanoid Robot Development: The Quest for Human-Like Machines","docId":"chapter_8_humanoid_robot_development","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_9_vision_language_action_models","label":"Chapter 9: Vision Language Action Models","docId":"chapter_9_vision_language_action_models","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_10_conversational_robotics","label":"Chapter 10: Conversational Robotics","docId":"chapter_10_conversational_robotics","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_11_sensor_systems","label":"Chapter 11: Sensor Systems","docId":"chapter_11_sensor_systems","unlisted":false},{"type":"link","href":"/physical-ai-robotics-textbook/docs/chapter_12_capstone_project","label":"Chapter 12: Capstone Project","docId":"chapter_12_capstone_project","unlisted":false}]},"docs":{"chapter_1_introduction_to_physical_ai":{"id":"chapter_1_introduction_to_physical_ai","title":"Chapter 1: Introduction to Physical AI","description":"Physical AI represents a fascinating and rapidly evolving intersection of artificial intelligence, robotics, and engineering. It moves beyond purely digital intelligence to encompass systems that can perceive, reason, and act within the physical world. Unlike traditional AI that primarily operates in software environments, Physical AI agents are embodied, meaning they exist within a physical form, whether as a robot arm, a mobile platform, or a humanoid structure. This embodiment allows them to interact directly with their surroundings, gather sensory data, and perform physical tasks, bringing AI out of the server rooms and into our daily lives.","sidebar":"tutorialSidebar"},"chapter_10_conversational_robotics":{"id":"chapter_10_conversational_robotics","title":"Chapter 10: Conversational Robotics","description":"Conversational robotics stands at the intersection of natural language processing, artificial intelligence, and physical robotics, enabling machines to engage in natural, intuitive dialogue with humans. This capability moves robots beyond simple command-line interfaces or pre-programmed responses, fostering a more engaging and effective mode of human-robot collaboration. The goal is to create robots that can understand spoken or written instructions, engage in meaningful conversations, provide information, and execute tasks based on dialogue, thereby enhancing user experience and broadening the applicability of robotic systems.","sidebar":"tutorialSidebar"},"chapter_11_sensor_systems":{"id":"chapter_11_sensor_systems","title":"Chapter 11: Sensor Systems","description":"Sensor systems are the eyes, ears, and touch of a robot, providing the crucial data necessary for perception, localization, mapping, and interaction with its environment. Without robust sensing capabilities, a robot would be blind, deaf, and unable to interact intelligently with the world. The careful selection, integration, and processing of sensor data are fundamental to developing any autonomous robotic system.","sidebar":"tutorialSidebar"},"chapter_12_capstone_project":{"id":"chapter_12_capstone_project","title":"Chapter 12: Capstone Project","description":"The capstone project serves as the culmination of your learning journey in robotics, offering a unique opportunity to synthesize theoretical knowledge with practical application. It is where you bring together concepts from perception, control, navigation, human-robot interaction, and AI to address a significant robotics challenge. This chapter outlines the typical lifecycle of a capstone project, providing guidance on defining, planning, implementing, and evaluating your work.","sidebar":"tutorialSidebar"},"chapter_2_embodied_intelligence":{"id":"chapter_2_embodied_intelligence","title":"Chapter 2: Embodied Intelligence","description":"Embodied intelligence is a core concept within Physical AI, asserting that intelligence does not reside solely in an abstract, disembodied mind, but is deeply intertwined with the physical body and its interactions with the environment. It challenges traditional AI paradigms that often separate cognition from perception and action, arguing that a physical form and the ability to act within the world are fundamental to the development of sophisticated intelligence. This chapter explores the principles of embodied intelligence, its implications for robotics, and how it differs from purely disembodied AI.","sidebar":"tutorialSidebar"},"chapter_3_ros2_fundamentals":{"id":"chapter_3_ros2_fundamentals","title":"Chapter 3: ROS2 Fundamentals","description":"The Robot Operating System (ROS) has become the de facto standard framework for robot software development. ROS2, the next generation of ROS, addresses many limitations of its predecessor, offering improved real-time capabilities, enhanced security, and better support for multi-robot systems and diverse hardware. This chapter introduces the fundamental concepts of ROS2, guiding you through its architecture, core components, and basic usage, which are essential for building sophisticated physical AI and humanoid robotics applications.","sidebar":"tutorialSidebar"},"chapter_4_ros2_advanced":{"id":"chapter_4_ros2_advanced","title":"Chapter 4: ROS2 Advanced","description":"Building upon the fundamentals of ROS2, this chapter delves into more advanced concepts and tools crucial for developing robust, scalable, and complex robotic applications. We will explore advanced communication patterns, quality of service (QoS) settings, state management, integration with external libraries, and best practices for large-scale ROS2 projects. Mastering these advanced topics is essential for tackling the intricacies of physical AI and humanoid robotics.","sidebar":"tutorialSidebar"},"chapter_5_robot_simulation_gazebo":{"id":"chapter_5_robot_simulation_gazebo","title":"Chapter 5: Robot Simulation Gazebo","description":"Robot simulation is an indispensable tool in the development lifecycle of physical AI and humanoid robotics. It allows engineers and researchers to design, test, and refine robot hardware and software in a safe, controlled, and cost-effective virtual environment before deployment on physical hardware. Gazebo, a powerful 3D robot simulator, stands out as a leading platform for this purpose, offering robust physics, realistic sensor models, and seamless integration with ROS2. This chapter will provide a comprehensive overview of Gazebo, from its core features to practical usage and integration with ROS2.","sidebar":"tutorialSidebar"},"chapter_6_unity_for_robotics":{"id":"chapter_6_unity_for_robotics","title":"Chapter 6: Unity for Robotics","description":"While Gazebo is a powerful simulator for classical robotics, game engines like Unity are increasingly being adopted for robotics simulation, especially in the context of physical AI and humanoid robotics. Unity offers a high-fidelity visual environment, advanced rendering capabilities, flexible physics engines, and a robust development ecosystem, making it an excellent platform for tasks requiring realistic perception, human-robot interaction, and reinforcement learning. This chapter explores how Unity can be leveraged for robotics simulation, its advantages, and practical approaches to integrating it with robotic frameworks.","sidebar":"tutorialSidebar"},"chapter_7_nvidi-isaac_platform":{"id":"chapter_7_nvidi-isaac_platform","title":"Chapter 7: NVIDIA Isaac Platform","description":"As physical AI and humanoid robotics become more sophisticated, the demand for powerful, specialized platforms for simulation, development, and deployment grows. The NVIDIA Isaac platform is a comprehensive suite of hardware, software, and tools designed to accelerate the development of AI-powered robots. It brings together NVIDIA\'s expertise in GPUs, AI, and simulation to provide an end-to-end solution for robotics. This chapter explores the key components of the NVIDIA Isaac platform, including Isaac Sim, Isaac SDK, and Jetson hardware, and demonstrates how they contribute to building advanced robotic applications.","sidebar":"tutorialSidebar"},"chapter_7_nvidia_isaac_platform":{"id":"chapter_7_nvidia_isaac_platform","title":"Chapter 7: NVIDIA Isaac Platform","description":"The NVIDIA Isaac Platform is a comprehensive robotics development platform designed to accelerate the creation, simulation, and deployment of AI-powered robots. It provides a full suite of software and hardware solutions, empowering developers to build sophisticated robotic applications that can perceive, reason, and act intelligently in complex environments. From manufacturing and logistics to healthcare and service industries, Isaac aims to democratize access to advanced robotics by offering a unified framework for perception, navigation, and manipulation."},"chapter_8_humanoid_robot_development":{"id":"chapter_8_humanoid_robot_development","title":"Chapter 8: Humanoid Robot Development: The Quest for Human-Like Machines","description":"Humanoid robots stand as a pinnacle of robotic engineering, embodying humanity\'s aspiration to create machines that not only mimic our form but also interact with the world in a human-centric manner. These bipedal, anthropomorphic machines are designed to operate in environments built for humans, utilize human tools, and engage in social interactions. This chapter delves into the multifaceted challenges and advancements in designing, sensing, controlling, and deploying humanoid robots.","sidebar":"tutorialSidebar"},"chapter_9_vision_language_action_models":{"id":"chapter_9_vision_language_action_models","title":"Chapter 9: Vision Language Action Models","description":"Vision-Language-Action Models (VLAMs) represent a paradigm shift in robotics, moving beyond siloed capabilities to integrate perception, communication, and physical execution into a cohesive framework. At their core, VLAMs aim to bridge the vast semantic gap between high-level human instructions, often expressed in natural language, and the low-level motor commands required to control a robot in the physical world. This integration is crucial for enabling robots to understand complex commands, learn from diverse data modalities, and operate more autonomously and flexibly in human-centric environments.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Tutorial Intro","description":"Let\'s discover Docusaurus in less than 5 minutes."},"tutorial-basics/congratulations":{"id":"tutorial-basics/congratulations","title":"Congratulations!","description":"You have just learned the basics of Docusaurus and made some changes to the initial template."},"tutorial-basics/create-a-blog-post":{"id":"tutorial-basics/create-a-blog-post","title":"Create a Blog Post","description":"Docusaurus creates a page for each blog post, but also a blog index page, a tag system, an RSS feed..."},"tutorial-basics/create-a-document":{"id":"tutorial-basics/create-a-document","title":"Create a Document","description":"Documents are groups of pages connected through:"},"tutorial-basics/create-a-page":{"id":"tutorial-basics/create-a-page","title":"Create a Page","description":"Add Markdown or React files to src/pages to create a standalone page:"},"tutorial-basics/deploy-your-site":{"id":"tutorial-basics/deploy-your-site","title":"Deploy your site","description":"Docusaurus is a static-site-generator (also called Jamstack)."},"tutorial-basics/markdown-features":{"id":"tutorial-basics/markdown-features","title":"Markdown Features","description":"Docusaurus supports Markdown and a few additional features."},"tutorial-extras/manage-docs-versions":{"id":"tutorial-extras/manage-docs-versions","title":"Manage Docs Versions","description":"Docusaurus can manage multiple versions of your docs."},"tutorial-extras/translate-your-site":{"id":"tutorial-extras/translate-your-site","title":"Translate your site","description":"Let\'s translate docs/intro.md to French."}}}}')}}]);